  (NULL, 'Proposal Follow-Up 1', 'Following up on our proposal', '<p>Hi {{client.preferred_name}},</p><p>Just checking in regarding the proposal we sent across.</p><p>Best regards,<br/>{{practice.name}}</p>', 'email', 'CRM_PROPOSAL_FOLLOWUP_1', true, '{"client.preferred_name": "string", "practice.name": "string"}'::jsonb),
